package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithCommentMarkerChar() {
        CSVFormat original = CSVFormat.DEFAULT;
        char commentChar = '#';

        CSVFormat result = original.withCommentMarker(commentChar);

        assertNotNull(result);
        assertEquals(Character.valueOf(commentChar), result.getCommentMarker());
        // Original instance should remain unchanged (immutability)
        assertNull(original.getCommentMarker());
    }

    @Test
    void testWithCommentMarkerCharacterNull() {
        CSVFormat original = CSVFormat.DEFAULT;

        CSVFormat result = original.withCommentMarker((Character) null);

        assertNotNull(result);
        assertNull(result.getCommentMarker());
        // Original instance should remain unchanged (immutability)
        assertNull(original.getCommentMarker());
    }

    @Test
    void testWithCommentMarkerCharacterSet() {
        CSVFormat original = CSVFormat.DEFAULT;
        Character commentChar = Character.valueOf('!');

        CSVFormat result = original.withCommentMarker(commentChar);

        assertNotNull(result);
        assertEquals(commentChar, result.getCommentMarker());
        // Original instance should remain unchanged (immutability)
        assertNull(original.getCommentMarker());
    }
}
